args.sqlite_command:
UPDATE J09B_temp
SET ENTSCHEIDUNG = (
  SELECT CASE WHEN COUNT(DISTINCT EQUNR) < 3 THEN 'KSA' ELSE 'EVU' END
  FROM J09B_temp jt
  WHERE jt.HAUS = J09B_temp.HAUS
);

UPDATE J09B_final
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (SELECT EQUNR FROM J09B_mandatory_eq);

args.sql_query:
SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09B_final
WHERE ENTSCHEIDUNG = 'MANDATORY_READING';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09B_final
WHERE ENTSCHEIDUNG = 'DIRECT_MAIL';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1, CITY2, EMAIL
FROM J09B_final
WHERE ENTSCHEIDUNG NOT IN ('MANDATORY_READING', 'DIRECT_MAIL') OR ENTSCHEIDUNG IS NULL;
